def select_action(obs: np.ndarray) -> int:
    """Select a Pong action from the 128-byte RAM state.

    The player controls the right paddle. A point is scored each time
    the ball passes the opponent's paddle; a point is lost when the
    ball passes the player's own paddle.

    Args:
        obs: 128-element uint8 array (ALE RAM).
            obs[49]: ball x  (17-160, left to right)
            obs[54]: ball y  (17-194, larger = lower on screen)
            obs[51]: player (right) paddle y center (34-194)
            obs[50]: CPU (left) paddle y center     (34-194)
    Returns:
        action: 0 (NOOP), 2 (UP), or 3 (DOWN)
    """
    ball_x = obs[49]
    ball_y = obs[54]
    paddle_y = obs[51]

    # Determine ball's vertical quadrant (0 top, 1 middle-top, 2 middle-bottom, 3 bottom)
    if ball_y < 61:
        ball_quadrant = 0
    elif ball_y < 105:
        ball_quadrant = 1
    elif ball_y < 149:
        ball_quadrant = 2
    else:
        ball_quadrant = 3

    # Determine paddle's vertical zone
    if paddle_y < 70:
        paddle_zone = 0
    elif paddle_y < 120:
        paddle_zone = 1
    else:
        paddle_zone = 2

    # Decision matrix based on ball quadrant and paddle zone, plus ball x influence
    if ball_x > 100:  # Ball on right side, react more precisely
        diff = ball_quadrant - paddle_zone
        if diff < -1:
            return 2
        elif diff > 1:
            return 3
        else:
            if ball_y < paddle_y - 5:
                return 2
            elif ball_y > paddle_y + 5:
                return 3
            return 0
    else:  # Ball on left, use coarse alignment
        if paddle_zone < 1 and ball_quadrant > 1:
            return 3
        elif paddle_zone > 1 and ball_quadrant < 1:
            return 2
        else:
            # Center drift
            if paddle_y < 105:
                return 3
            elif paddle_y > 105:
                return 2
            return 0
